"use strict";(self.webpackChunkpims_manual=self.webpackChunkpims_manual||[]).push([[8581],{5610:e=>{e.exports=JSON.parse('{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"tutorialSidebar":[{"type":"link","label":"Introduction","href":"/pimsKB/docs/intro","docId":"intro","unlisted":false},{"type":"category","label":"Appendix","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"Appendix A \u2013 Course Codes","href":"/pimsKB/docs/Appendix/appendix-A","docId":"Appendix/appendix-A","unlisted":false},{"type":"link","label":"Appendix B \u2013 Staff Assignment Codes","href":"/pimsKB/docs/Appendix/appendix-B","docId":"Appendix/appendix-B","unlisted":false},{"type":"link","label":"Appendix C \u2013 Highest Level of Education Completed","href":"/pimsKB/docs/Appendix/appendix-C","docId":"Appendix/appendix-C","unlisted":false},{"type":"link","label":"Appendix D \u2013 State and County Codes","href":"/pimsKB/docs/Appendix/appendix-D","docId":"Appendix/appendix-D","unlisted":false},{"type":"link","label":"Appendix E \u2013 Enrollment and Withdrawal Codes","href":"/pimsKB/docs/Appendix/appendix-E","docId":"Appendix/appendix-E","unlisted":false},{"type":"link","label":"Appendix F \u2013 Program Codes","href":"/pimsKB/docs/Appendix/appendix-F","docId":"Appendix/appendix-F","unlisted":false},{"type":"link","label":"Appendix G \u2013 Employment Eligibility Verification Codes","href":"/pimsKB/docs/Appendix/appendix-G","docId":"Appendix/appendix-G","unlisted":false},{"type":"link","label":"Appendix H \u2013 Disability Codes (Challenge Types)","href":"/pimsKB/docs/Appendix/appendix-H","docId":"Appendix/appendix-H","unlisted":false}]},{"type":"category","label":"Templates","collapsible":true,"collapsed":true,"items":[{"type":"category","label":"Enrollment","collapsible":true,"collapsed":true,"items":[{"type":"link","label":"School Enrollment Template","href":"/pimsKB/docs/Templates/Enrollment/school-enrollment-template","docId":"Templates/Enrollment/school-enrollment-template","unlisted":false}]},{"type":"link","label":"Templates","href":"/pimsKB/docs/Templates/intro","docId":"Templates/intro","unlisted":false}]},{"type":"link","label":"Courses to be Reported in PIMS","href":"/pimsKB/docs/courses-to-be-reported","docId":"courses-to-be-reported","unlisted":false},{"type":"link","label":"Curriculum, Assessment, and Instruction","href":"/pimsKB/docs/curriculum-assessment-instruction","docId":"curriculum-assessment-instruction","unlisted":false},{"type":"link","label":"Race, Ethnicity, Gender","href":"/pimsKB/docs/race-ethnicity-gender-standards","docId":"race-ethnicity-gender-standards","unlisted":false},{"type":"link","label":"Staff to be Reported in PIMS","href":"/pimsKB/docs/staff-to-be-reported","docId":"staff-to-be-reported","unlisted":false},{"type":"link","label":"Students to be Reported in PIMS","href":"/pimsKB/docs/students-to-be-reported","docId":"students-to-be-reported","unlisted":false}]},"docs":{"Appendix/appendix-A":{"id":"Appendix/appendix-A","title":"Appendix A \u2013 Course Codes","description":"Course Codes are found in the Course Codes \u2013 App A spreadsheet on the Pennsylvania Department of Education \\\\> Data and Reporting \\\\> PIMS \\\\> Manuals and Calendar page.","sidebar":"tutorialSidebar"},"Appendix/appendix-B":{"id":"Appendix/appendix-B","title":"Appendix B \u2013 Staff Assignment Codes","description":"Chief School Administrator Assignment Codes (numerical order) are found in the Staff Assignments \u2013","sidebar":"tutorialSidebar"},"Appendix/appendix-C":{"id":"Appendix/appendix-C","title":"Appendix C \u2013 Highest Level of Education Completed","description":"Appendix C is for use with Field 71 (HIGHEST DEGREE INSTITUTION CODE) in the Staff and Staff Snapshot Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-D":{"id":"Appendix/appendix-D","title":"Appendix D \u2013 State and County Codes","description":"State Codes","sidebar":"tutorialSidebar"},"Appendix/appendix-E":{"id":"Appendix/appendix-E","title":"Appendix E \u2013 Enrollment and Withdrawal Codes","description":"The codes listed below are only to be used for Field 6 (ENROLLMENT CODE) in the School Enrollment Template. These codes do not replace any existing codes that may be native to your local Student Information System (SIS). Please continue to use enrollment codes in your SIS which support other purposes, such as Child Accounting aggregate calculations, scheduling changes, room changes, etc. The codes listed in the table below are the only codes that will be accepted in the School Enrollment Template submission to PIMS.","sidebar":"tutorialSidebar"},"Appendix/appendix-F":{"id":"Appendix/appendix-F","title":"Appendix F \u2013 Program Codes","description":"The programs listed below are tracked using the Program Fact Template.","sidebar":"tutorialSidebar"},"Appendix/appendix-G":{"id":"Appendix/appendix-G","title":"Appendix G \u2013 Employment Eligibility Verification Codes","description":"Appendix G is for use with Field 83 (EMPLOYMENT ELIGIBILITY VERIFICATION) in the Staff and Staff Snapshot Templates.","sidebar":"tutorialSidebar"},"Appendix/appendix-H":{"id":"Appendix/appendix-H","title":"Appendix H \u2013 Disability Codes (Challenge Types)","description":"Appendix H is for use with Field 34 (CHALLENGE TYPE) in the Student and Student Snapshot Templates, and Field 11 (PRIMARY DISABILITY) and Field 12 (SECONDARY DISABILITY) in the Special Education Snapshot Template.","sidebar":"tutorialSidebar"},"courses-to-be-reported":{"id":"courses-to-be-reported","title":"Courses to be Reported in PIMS","description":"LEAs are required to submit all courses, course instructor assignments, and student course enrollments, in all academic subject areas for both elementary and secondary. To meet federal reporting requirements, LEAs are expected to map all local courses to state course codes (PIMS \\\\> Manuals and Calendar \\\\> Course Codes \u2013 App A).","sidebar":"tutorialSidebar"},"curriculum-assessment-instruction":{"id":"curriculum-assessment-instruction","title":"Curriculum, Assessment, and Instruction","description":"Division of Assessment and Accountability (DAA)","sidebar":"tutorialSidebar"},"intro":{"id":"intro","title":"Introduction","description":"The Pennsylvania Information Management System (PIMS) is a collaborative effort of the Pennsylvania Department of Education (PDE) and local education agencies (LEA) across the commonwealth. PIMS is a statewide, longitudinal data system (SLDS) that efficiently and accurately manages, analyzes, disaggregates, and uses individual data for each student served by Pennsylvania\u2019s pre-K through grade 12 public education system.","sidebar":"tutorialSidebar"},"race-ethnicity-gender-standards":{"id":"race-ethnicity-gender-standards","title":"Race, Ethnicity, Gender","description":"Federal Race, Ethnicity, and Gender Standards","sidebar":"tutorialSidebar"},"staff-to-be-reported":{"id":"staff-to-be-reported","title":"Staff to be Reported in PIMS","description":"Professional Personnel","sidebar":"tutorialSidebar"},"students-to-be-reported":{"id":"students-to-be-reported","title":"Students to be Reported in PIMS","description":"All Pre-K through grade 12 and Adult Affidavit Program (AAP) students enrolled in a public school and students enrolled in an Approved Private School (APS) or Private Residential Rehabilitation Institution (PRRI) in Pennsylvania shall be reported in PIMS. Student data will be submitted through templates. See the template section of this document for more information.","sidebar":"tutorialSidebar"},"Templates/Enrollment/school-enrollment-template":{"id":"Templates/Enrollment/school-enrollment-template","title":"School Enrollment Template","description":"School Enrollment Template Documentation","sidebar":"tutorialSidebar"},"Templates/intro":{"id":"Templates/intro","title":"Templates","description":"Templates are the files that will be used to load data into the PIMS data warehouse. Template specifications define the fields required for each file submitted to PIMS. Each template maps directly to a separate table in the data warehouse. By using templates, LEAs are able to use a variety of file formats (comma delimited, tab delimited, pipe) to transmit data as long as all fields within the template are accounted for. Within a given template not all eScholar-defined fields are collected by PDE.","sidebar":"tutorialSidebar"}}}')}}]);